#include <stdio.h>
#include <math.h>
#define MOD 998244353

long long gcd(long long a, long long b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

long long powmod(long long a, long long b, long long mod) {
    long long res = 1;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

long long F(long long n) {
    long long res = 1;
    for (long long i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            long long cnt = 0;
            while (n % i == 0) {
                n /= i;
                cnt++;
            }
            res = (res * i) % MOD;
        }
    }
    if (n > 1) res = (res * n) % MOD;
    return res;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long sum = 0;
        for (long long i = 2; i <= N; i++) {
            sum = (sum + F(i)) % MOD;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

